import{_ as i,o as l,c as t,a2 as e}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F14: 負債結構與償債壓力測試 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3135_凌航/20260430/F14_負債結構與償債壓力測試_投資研究員.md","filePath":"審計報告庫/財務審計/3135_凌航/20260430/F14_負債結構與償債壓力測試_投資研究員.md"}'),r={name:"審計報告庫/財務審計/3135_凌航/20260430/F14_負債結構與償債壓力測試_投資研究員.md"};function n(o,a,s,h,c,d){return l(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="f14-負債結構與償債壓力測試-投資研究員-審計報告" tabindex="-1">F14: 負債結構與償債壓力測試 - 投資研究員 審計報告 <a class="header-anchor" href="#f14-負債結構與償債壓力測試-投資研究員-審計報告" aria-label="Permalink to &quot;F14: 負債結構與償債壓力測試 - 投資研究員 審計報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>負債比率與利息覆蓋倍數為何？債務到期分佈是否集中於短期？在高利率環境下的利息支出承受度為何？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：負債比59%、短債佔有息負債47.7%，ICR一度跌至2.06x；還款壓力集中短債，結構性脆弱。</li><li><strong>風險評級</strong>：中高</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：負債比59%、短債佔有息負債47.7%、現金覆蓋僅5%、淨負債/EBITDA 5.74x。</li><li><strong>診斷見解</strong>：18個月內急劇槓桿化，負債從9.76億膨脹至30.55億。Q2因季節性低谷ICR跌至2.06x，暴露高槓桿脆弱性。全年營業現金流負17.74億，以債維生。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、負債比率與利息覆蓋倍數趨勢" tabindex="-1">一、負債比率與利息覆蓋倍數趨勢 <a class="header-anchor" href="#一、負債比率與利息覆蓋倍數趨勢" aria-label="Permalink to &quot;一、負債比率與利息覆蓋倍數趨勢&quot;">​</a></h3><ul><li><strong>核心重點</strong>：ICR從Q1的5.30x急墜至Q2的2.06x，再回升至Q4的10.00x，波動達5倍。</li><li><strong>深度見解</strong>：Q2虧損觸及B級警戒，暴露DRAM/NAND現貨價波動的季節性風險，公司缺乏穩定的利息防禦緩衝。</li></ul><h3 id="二、債務到期分佈與短期流動性" tabindex="-1">二、債務到期分佈與短期流動性 <a class="header-anchor" href="#二、債務到期分佈與短期流動性" aria-label="Permalink to &quot;二、債務到期分佈與短期流動性&quot;">​</a></h3><ul><li><strong>核心重點</strong>：短期借款12.21億(47.7%)，現金覆蓋率僅5%。</li><li><strong>深度見解</strong>：高度依賴銀行續貸，一旦授信收緊或產業下行觸發風控，將面臨流動性危機。</li></ul><h3 id="三、高利率環境利息承受度" tabindex="-1">三、高利率環境利息承受度 <a class="header-anchor" href="#三、高利率環境利息承受度" aria-label="Permalink to &quot;三、高利率環境利息承受度&quot;">​</a></h3><ul><li><strong>核心重點</strong>：平均利率2.31%，升100bp侵蝕稅前淨利6.0%。</li><li><strong>深度見解</strong>：衝擊可控，但利率疊加產業下行雙重壓力下，營收若下滑20%將觸發ICR降至6.6x。</li></ul><h3 id="四、可轉換公司債結構影響" tabindex="-1">四、可轉換公司債結構影響 <a class="header-anchor" href="#四、可轉換公司債結構影響" aria-label="Permalink to &quot;四、可轉換公司債結構影響&quot;">​</a></h3><ul><li><strong>核心重點</strong>：兩檔合計25億CB、0%利率，若未轉換到期須一次性籌措25億本金。</li><li><strong>深度見解</strong>：轉換價50.85元，若股價長期低於此水準，到期需巨額還本，對2028-2029年現金流構成結構性壓力。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：營業現金流持續為負。2025全年營業活動淨現金流出17.74億，存貨從7.14億暴增至26.19億(增長267%)，應收帳款從8.82億增至14.99億(增長70%)。營運資金被大量佔用，若記憶體價格反轉下跌，存貨減值將直接侵蝕權益，同時觸發銀行抽銀根，形成「存貨跌價→信用收縮→流動性危機」的死亡螺旋。</li><li><strong>空頭風險二</strong>：槓桿擴張速度異常。18個月內負債從9.76億膨脹至30.55億(增長213%)，而同期營收僅增長71%(30.74億→52.61億)。負債增速是營收增速的3倍，若營收增長放緩或下滑，高槓桿將迅速放大虧損。記憶體產業的強週期特性意味著「好年」與「壞年」的切換可能在2-3個季度內完成，公司的槓桿結構在下行週期中缺乏緩衝空間。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK，balance_sheet/cash_flow/finance三表交叉校驗完成</li><li><strong>yfinance</strong>: 未使用（FinMind數據已充足）</li><li><strong>年報/法說</strong>: OK，112年年報PDF提取借款利率(0.5%-7.31%)、質抵押資產(2.32億)、流動比率(210.57%)</li><li><strong>關鍵核對碼</strong>: <ul><li>2025Q4負債總額: 3,055,466千 (FinMind balance_sheet)</li><li>2025FY利息費用: 42,546千 (FinMind cash_flow)</li><li>2025FY營業利益: 425,582千 (FinMind finance)</li><li>2025Q4短期借款: 1,221,007千 / 長期借款: 402,400千 / 應付公司債: 937,507千 (FinMind balance_sheet)</li><li>凌航一CB: 10億, 0%利率, 到期2028/12/4 (公開資訊觀測站)</li><li>凌航二CB: 15億上限, 0%利率, 轉換價129.9元 (公開資訊觀測站)</li></ul></li></ul>',21)])])}const g=i(r,[["render",n]]);export{u as __pageData,g as default};
